export interface Task {
  id: string;
  title: string;
  description: string;
  completed: boolean;
  userId: string;
  createdAt: string;
  updatedAt: string;
}

export const tasks: Map<string, Task> = new Map();

export function createTask(data: Omit<Task, 'id' | 'createdAt' | 'updatedAt'>): Task {
  const task: Task = {
    ...data,
    id: Math.random().toString(36).slice(2),
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString(),
  };
  tasks.set(task.id, task);
  return task;
}

export function getTask(id: string): Task | undefined {
  return tasks.get(id);
}

export function updateTask(id: string, data: Partial<Task>): Task | null {
  const task = tasks.get(id);
  if (!task) return null;
  const updated = { ...task, ...data, updatedAt: new Date().toISOString() };
  tasks.set(id, updated);
  return updated;
}

export function deleteTask(id: string): boolean {
  return tasks.delete(id);
}

import { Request, Response, NextFunction } from 'express';
import jwt from 'jsonwebtoken';

const JWT_SECRET = process.env.JWT_SECRET ?? 'dev-secret';

export interface AuthRequest extends Request {
  userId?: string;
}

export function requireAuth(req: AuthRequest, res: Response, next: NextFunction): void {
  const header = req.headers.authorization;
  if (!header?.startsWith('Bearer ')) {
    res.status(401).json({ error: 'Missing or invalid authorization header' });
    return;
  }
  const token = header.slice(7);
  try {
    const payload = jwt.verify(token, JWT_SECRET) as { userId: string };
    req.userId = payload.userId;
    next();
  } catch {
    res.status(401).json({ error: 'Invalid or expired token' });
  }
}

import { Router } from 'express';
import { requireAuth, AuthRequest } from '../middleware/auth';
import { createTask, getTask, updateTask, deleteTask, tasks } from '../models/task';

const router = Router();

router.get('/', requireAuth, (req: AuthRequest, res) => {
  const userTasks = [...tasks.values()].filter(t => t.userId === req.userId);
  res.json(userTasks);
});

router.post('/', requireAuth, (req: AuthRequest, res) => {
  const { title, description } = req.body;
  if (!title) {
    res.status(400).json({ error: 'title is required' });
    return;
  }
  const task = createTask({ title, description: description ?? '', completed: false, userId: req.userId! });
  res.status(201).json(task);
});

router.get('/:id', requireAuth, (req: AuthRequest, res) => {
  const task = getTask(req.params.id);
  if (!task || task.userId !== req.userId) {
    res.status(404).json({ error: 'Task not found' });
    return;
  }
  res.json(task);
});

router.patch('/:id', requireAuth, (req: AuthRequest, res) => {
  const task = getTask(req.params.id);
  if (!task || task.userId !== req.userId) {
    res.status(404).json({ error: 'Task not found' });
    return;
  }
  const updated = updateTask(req.params.id, req.body);
  res.json(updated);
});

router.delete('/:id', requireAuth, (req: AuthRequest, res) => {
  const task = getTask(req.params.id);
  if (!task || task.userId !== req.userId) {
    res.status(404).json({ error: 'Task not found' });
    return;
  }
  deleteTask(req.params.id);
  res.status(204).send();
});

export default router;

