import { Request, Response, NextFunction } from 'express';

export function validateTaskUpdate(req: Request, res: Response, next: NextFunction): void {
  const allowed = new Set(['title', 'description', 'completed']);
  const keys = Object.keys(req.body);
  const invalid = keys.filter(k => !allowed.has(k));
  if (invalid.length > 0) {
    res.status(400).json({ error: `Invalid fields: ${invalid.join(', ')}` });
    return;
  }
  next();
}
